/**
 * pi-conductor extension entrypoint — Phase 7B.
 *
 * Wraps the production host driver (`src/host/`) in a pi
 * extension that exposes four slash commands:
 *
 *   - `/conduct <goal>`         — start a run.
 *   - `/conduct:resume <run_id>` — resume a run from its log.
 *   - `/conduct:list`           — list known runs in the log.
 *   - `/conduct:abort`          — abort the active run.
 *
 * plus one CLI flag:
 *
 *   - `--conduct-manifest <path>` — override the default
 *     manifest path. Default: `<ctx.cwd>/.pi/conductor.yaml`.
 *
 * ## Why this is a UX shell, not the engine
 *
 * The spec (§9.5) and the extension pivot plan both make this
 * explicit: the orchestration engine is the SDK host driver in
 * `src/host/`, which spawns role sessions via the standalone
 * `createAgentSession` (not via `ctx.newSession()` or
 * `ctx.fork`). This extension is the **shell** — the four
 * commands are thin handlers that resolve the manifest,
 * construct a `ProductionHost` via `createProductionHost`,
 * and forward to `startRun` / `resumeRun` / `listRuns` /
 * `RunHandle.abort`.
 *
 * The grep-guard test `tests/extension/no-role-spawn-via-session-tree.test.ts`
 * asserts this separation: the extension never calls
 * `ctx.newSession` or `ctx.fork`. Role sessions are spawned
 * by `ProductionHost` only.
 *
 * ## Factory discipline
 *
 * `the pi extensions spec` is explicit: the factory may run in
 * invocations that never start a session (e.g. `pi --help`).
 * No `startRun` / `resumeRun` / file I/O / polling starts
 * from this function. The factory only registers commands
 * and the flag; all long-lived work begins in the command
 * handlers. The 7B.1 acceptance is verified by
 * `tests/extension/conduct.test.ts` (the harness test asserts
 * the active-run tracker is still `null` after factory
 * returns).
 *
 * ## `default` export (the explicit exception to AGENTS.md)
 *
 * AGENTS.md says "named exports only". `the pi extensions spec`
 * + pi's `ExtensionFactory` type require the entrypoint to
 * be the module's `default` export — pi's loader calls
 * `await jiti.import(extensionPath, { default: true })` and
 * resolves the default-exported function as the factory.
 * This file is the single explicit exception; all other
 * modules in `extensions/` use named exports.
 *
 * ## Module size
 *
 * This file is the registration entrypoint only. The four
 * command handlers live in `extensions/commands/*.ts` to
 * keep each file under the AGENTS.md ~400-LOC ceiling. The
 * factory itself registers + dispatches; the work happens
 * in the handlers.
 */

import type { ExtensionAPI } from "@earendil-works/pi-coding-agent";

import { handleAbort } from "../src/extension/commands/abort.js";
import { handleList } from "../src/extension/commands/list.js";
import { handleResume } from "../src/extension/commands/resume.js";
import {
  type GetFlagValue,
  type HandleDeps,
  handleStart,
} from "../src/extension/commands/start.js";
import { createConductMessageRenderers } from "../src/extension/conduct-message-renderer.js";
import { getCurrentOrchestratorRole } from "../src/extension/current-orchestrator.js";
import { createConductDisplaySink } from "../src/extension/display-sink-wiring.js";
import { subscribeToRecords } from "../src/host/index.js";

/**
 * Manifest path override flag. Default is resolved at
 * command time by `resolveManifestPath(flagValue, ctx.cwd)`
 * — the extension does not pin a default on the flag
 * itself (the resolver owns the rule).
 */
const CONDUCT_MANIFEST_FLAG = "conduct-manifest";

/**
 * Adapt the SDK's `(args, ctx)` handler shape to the
 * extension's `(args, ctx, deps)` shape. The deps carry
 * the flag reader — a `pi.getFlag` closure the factory
 * creates once and shares across all four handlers.
 */
function withDeps(
  handler: (
    args: string,
    ctx: Parameters<typeof handleStart>[1],
    deps: HandleDeps,
  ) => Promise<void>,
  getFlag: GetFlagValue,
  displaySink: HandleDeps["displaySink"],
  homeDir?: string,
): (args: string, ctx: Parameters<typeof handleStart>[1]) => Promise<void> {
  return (args, ctx) =>
    handler(args, ctx, {
      getFlag,
      ...(displaySink !== undefined && { displaySink }),
      ...(homeDir !== undefined && { homeDir }),
    });
}

/**
 * The extension factory. Called once per pi process.
 * Synchronous (no async work needed for registration;
 * the harness `await`s the return value, so a returned
 * `Promise<void>` would also work, but registration is
 * fast enough that sync is clearer).
 */
export default function conductExtension(pi: ExtensionAPI): void {
  pi.registerFlag(CONDUCT_MANIFEST_FLAG, {
    description: "Override the conductor manifest path (default: <cwd>/.pi/conductor.yaml)",
    type: "string",
  });

  // Single flag reader shared across all four handlers.
  // The closure reads the latest flag value at command
  // time, so a `--flag` set on the pi CLI line flows
  // into the handler invocation.
  const getFlag: GetFlagValue = (name) => pi.getFlag(name);
  const displaySink = createConductDisplaySink((message) => pi.sendMessage(message));

  // Conductor-owned message renderer for the
  // `conduct.role.text` `CustomMessage` `customType`. The
  // renderer takes over `CustomMessage` rendering for streamed
  // text entries and presents them with a bold structural
  // role label + a properly-themed markdown body (see
  // `src/extension/conduct-message-renderer.ts` for the
  // design and `the TUI bridge polish spec`
  // for the rationale). Phase 5.5 removed the
  // `conduct.role.tool` registration — the sink suppresses tool
  // events, so that renderer was dead code. The orchestrator-role
  // getter is resolved per-render against the live
  // `currentOrchestratorRole` slot, so the same renderer
  // instance works across runs.
  for (const [customType, renderer] of Object.entries(
    createConductMessageRenderers(getCurrentOrchestratorRole),
  )) {
    pi.registerMessageRenderer(customType, renderer);
  }

  pi.registerCommand("conduct", {
    description: "Start a pi-conductor run for <goal> using .pi/conductor.yaml.",
    handler: withDeps(handleStart, getFlag, displaySink),
  });

  pi.registerCommand("conduct:resume", {
    description: "Resume a previously-started run by run_id.",
    handler: withDeps(handleResume, getFlag, displaySink),
  });

  pi.registerCommand("conduct:list", {
    description: "List known runs in the conductor log.",
    handler: withDeps(handleList, getFlag, displaySink),
  });

  pi.registerCommand("conduct:abort", {
    description: "Abort the active run (no-op if none).",
    handler: withDeps(handleAbort, getFlag, displaySink),
  });

  /**
   * Opt-in `pi.events` bridge (spec §8.5, record-emitter-spec.md).
   *
   * Re-emits every PersistedRecord to the pi process event bus as
   * `"conductor:record"`.  Consumers that prefer the documented
   * `pi.events` API (`pi.events.on("conductor:record", ...)`) get
   * automatic delivery without importing `subscribeToRecords`
   * directly.  Consumers that call `subscribeToRecords` directly
   * don't need this bridge.
   *
   * This is a thin listener — it does not affect the engine.
   * The bridge delegates to `pi.events.emit`; the pi runtime
   * handles listener dispatch.  No `ctx.newSession` or
   * `ctx.fork` — `pi.events` is a lightweight pub/sub bus.
   */
  subscribeToRecords((record) => {
    pi.events.emit("conductor:record", record);
  });
}

/**
 * pi-conductor public entrypoint.
 *
 * Phase 1 (foundation): re-exports the pure FSM types from `src/core`.
 * Phase 2 adds the pure reducer (`reduce` / `createInitialCheckpoint`) +
 *   cap-aware legal-target helpers.
 * Phase 3 adds: the seam (TypeBox schemas + `validateEmission`),
 *   `reduceLifecycle`, pure cost roll-up + cap predicates (`src/cost`),
 *   the `RecordLog` interface + in-memory impl (`src/persistence`), and
 *   the run-memory builder (`src/core/run-memory.ts`).
 * Host-agnosticism invariant (spec §12): `src/core`, `src/manifest`,
 * `src/seam`, and `src/cost` import nothing from
 * `@earendil-works/pi-coding-agent`; enforced by `tests/grep-guard.test.ts`.
 */

export const PACKAGE_NAME = "pi-conductor";

// ─── Pure FSM types (spec §5, §7, §11, §12) ────────────────────────────
// Type-only re-exports. `verbatimModuleSyntax` keeps these out of the
// runtime JS bundle while giving consumers a single import surface.

export type {
  ActiveRoleSession,
  Checkpoint,
  Effect,
  LegalTargets,
  MachineDefinition,
  MachineEvent,
  ModelEffort,
  ModelFallback,
  PayloadSummary,
  ReduceLifecycleMeta,
  RejectReason,
  Role,
  SessionLifecycleEvent,
  State,
  TransitionAccepted,
  TransitionRejected,
  TransitionResult,
  UsageRecord,
} from "./core/types.js";
export { DEFAULT_MODEL_EFFORT } from "./core/types.js";

// ─── Cap-aware legal-target helpers (§7.2 / §7.4) ─────────────────────
// Phase 2 Task 5. Pure; used by the reducer for `legal_targets` on a
// `transition_rejected` record (§11.3) and by anything else that wants
// to surface the topology / cap state.

export { availableTargets, declaredTargets } from "./core/targets.js";

// Reducer signatures: `reduce` + `createInitialCheckpoint` are implemented in
// Phase 2 (Tasks 6–7, src/core/reduce.ts). `reduceLifecycle` lands in
// Phase 3 (Task 10, src/core/reduce-lifecycle.ts).

export { createInitialCheckpoint, ReduceInvariantError, reduce } from "./core/reduce.js";
export { ReduceLifecycleError, reduceLifecycle } from "./core/reduce-lifecycle.js";

// ─── Manifest types + parser (spec §8) ────────────────────────────────
// Type-only re-exports for the on-disk shape; runtime values for the
// parser + the typed error so consumers can `import { parseManifest }`
// and `catch (e) { if (e instanceof ManifestParseError) ... }`.

export { parseManifest } from "./manifest/parse.js";
export type { Manifest, ModelConfig, RoleConfig } from "./manifest/types.js";
export { ManifestParseError } from "./manifest/types.js";

// ─── Manifest validation + derivation (§13, §12) ──────────────────────
// validateManifest surfaces hard errors vs soft warnings; toMachineDefinition
// throws on hard errors and produces the frozen MachineDefinition snapshot
// the reducer (Phase 2) consumes as `def`.

export { toMachineDefinition } from "./manifest/definition.js";
export type {
  ManifestError,
  ManifestErrorCode,
  ManifestReport,
  ManifestWarning,
  ManifestWarningCode,
} from "./manifest/validate.js";
export { validateManifest } from "./manifest/validate.js";

// ─── Seam: TypeBox schemas + validateEmission (§3, §11.3) ─────────────
// Phase 3 Task 9. The TypeBox schemas are the single source of truth
// for `handoff`/`end` payload shape — they are reused as `defineTool`
// param schemas in Phase 4 (no second-schema double truth). The
// `HandoffArgs` / `EndArgs` types are the host's typed view of a
// validated payload (for seeding the next session); the reducer never
// sees them (§3/§12: payload is `unknown`).

export { summarizePayload } from "./seam/payload-summary.js";
export type { EndArgs, HandoffArgs } from "./seam/schema.js";
export { endArgsSchema, handoffArgsSchema } from "./seam/schema.js";
export type {
  BreachFailureReason,
  EmissionCapture,
  ValidatedEmission,
} from "./seam/validate-emission.js";
export { validateEmission } from "./seam/validate-emission.js";

// ─── Cost: pure usage roll-up + cap predicates (§11.6, §11.7) ─────────
// Phase 3 Task 11. The host calls these on every `turn_end` (session
// cap) and every terminal usage capture (run cap). Reducer does NOT
// own cost-cap enforcement (§11.7); these are the deterministic
// building blocks.
//
// Rollup is keyed by `run_id` and takes the orchestrator role name
// (the manifest's `is_orchestrator: true` entry) for the §11.6
// orchestrator-overhead isolation. Cache caveat (§11.6): the rollup
// exposes raw `cache_read` / `cache_write` sums; it does NOT
// synthesize a per-run cache hit rate.

export { runCapExceeded, sessionCapExceeded } from "./cost/caps.js";
export type { RunRollup, UsageAggregate } from "./cost/rollup.js";
export { rollup, SYSTEM_DEFAULT_MODEL_KEY } from "./cost/rollup.js";

// ─── Persistence: RecordLog interface + InMemoryRecordLog (§11.1) ──────
// Phase 3 Task 12. The pure core ships the interface and an in-memory
// implementation for unit tests; the Phase 4 host driver owns the
// file-backed implementation (append-only JSONL keyed by run_id; no
// SDK branch scoping, §11.1).
//
// CheckpointSnapshot (§11.1) wraps a full Checkpoint so `latestCheckpoint`
// reads the last snapshot — never replays records. The host's resume
// path (§11.9) reconstructs from this single read.

export type { CheckpointSnapshot, PersistedRecord, RecordLog } from "./persistence/log.js";
export { InMemoryRecordLog } from "./persistence/log.js";

// ─── Run memory artifact (§8.4) ───────────────────────────────────────
// Phase 3 Task 12. The orchestrator's externalized memory: a single
// structured record seeded into every fresh orchestrator session.
// Pure builder; no I/O. The host calls this before each orchestrator
// session starts to compose the seed context.

export type {
  BuildRunMemoryOptions,
  LastMessage,
  RoleCostEntry,
  RunMemory,
  VisitHistoryEntry,
} from "./core/run-memory.js";
export { buildRunMemory } from "./core/run-memory.js";

// ─── Host (SDK driver) — spec §8, §12, §15.3 ──────────────────────────
// Phase 4 (Tasks 13–16.5). This is the ONLY entrypoint that imports the
// pi SDK (`@earendil-works/pi-coding-agent`). The pure core above is
// host-agnostic; the host programs against it.
//
// Task 13 ships the manifest loader + the `Host` seam. The actual
// SDK-backed `Host` implementation, the file-backed `RecordLog`,
// `startRun` / `resumeRun` / `listRuns` / `RunHandle`, the orchestration
// loop, the post-emission sealing wrapper, the stub provider, and the
// orchestrator run-memory seeding land in subsequent tasks (13.5, 14,
// 15, 15.5, 16, 16.5).
//
// The grep-guard test (`tests/grep-guard.test.ts`) scans source as text
// for the SDK package name in `src/core` + `src/manifest` + `src/seam` +
// `src/cost`; `src/host/` is by exclusion the only allowed home.

// ─── Run lifecycle entry points (Task 13.5, §11.1, §11.9) ───────────
export type {
  ActiveSessionStats,
  applyRunConfigOverride,
  CreateProductionHostInputs,
  DefaultBundle,
  DisplayEvent,
  DisplayEventKind,
  DisplaySink,
  ExtensionContextInputs,
  getDefaultBundle,
  getDefaultConductorYaml,
  getDefaultOrchestratorPrompt,
  getDefaultWorkerPrompt,
  Host,
  HostFactoryContext,
  LoadedManifest,
  ProductionHostOptions,
  ResumeRunOptions,
  RoleSession,
  RunConfigError,
  RunConfigOverride,
  RunContextInputs,
  RunExecutionStatus,
  RunStats,
  runStats,
  SeedRunMemoryArgs,
  SpawnRoleOptions,
  StartRunOptions,
  StubHostOptions,
  TransitionRecord,
} from "./host/index.js";
export {
  AskUserUnavailableError,
  buildToolsAllowlist,
  createAskUserTool,
  createProductionHost,
  FileRecordLog,
  formatRunMemorySeed,
  HostManifestError,
  listRuns,
  loadManifest,
  loadManifestFromString,
  loadSystemPrompt,
  MalformedModelEntryError,
  ModelNotFoundError,
  NoMoreModelsError,
  ProductionHost,
  RoleEscalationError,
  RunHandle,
  resolveModel,
  resumeRun,
  StubHost,
  SystemPromptNotFoundError,
  selectModelEntry,
  startRun,
  subscribeToRecords,
} from "./host/index.js";

/**
 * `PersistedRecord` union and the `RecordLog` interface — spec §11.1–§11.5.
 *
 * Every record the host appends to its `run_id`-keyed append-only log is
 * a member of `PersistedRecord`. The union covers:
 *
 *  - §11.2 `transition_accepted`
 *  - §11.3 `transition_rejected`
 *  - §11.4 `session_started` / `session_ended` / `session_failed`
 *  - §11.5 `model_fallback`
 *  - §11.1 `checkpoint_snapshot` (the wrapper around the full `Checkpoint`
 *    the host appends after every accepted/rejected transition so
 *    `latestCheckpoint(runId)` is a read of the last snapshot, not an
 *    event-sourced replay — §11.1 explicitly forbids replay).
 *
 * **`RecordLog`** is the host-side persistence contract. The pure core
 * ships the interface and an in-memory implementation for unit tests.
 * The Phase 4 host driver owns the file-backed implementation
 * (append-only JSONL keyed by `run_id`; no SDK branch scoping, §11.1).
 *
 * Host-agnostic. No pi imports, no real I/O.
 */

import type {
  Checkpoint,
  ModelFallback,
  SessionLifecycleEvent,
  TransitionAccepted,
  TransitionRejected,
} from "../core/types.js";

/**
 * §11.1: a checkpoint snapshot is a full Checkpoint, snapshotted after
 * every accepted/rejected transition (and on lifecycle changes that
 * affect `active_role_session`). The host appends it to its log; resume
 * reads the latest snapshot — never replays records.
 */
export interface CheckpointSnapshot {
  readonly type: "checkpoint_snapshot";
  readonly checkpoint: Checkpoint;
}

/** Union of every record the host appends to its run_id-keyed log. */
export type PersistedRecord =
  | TransitionAccepted
  | TransitionRejected
  | SessionLifecycleEvent
  | ModelFallback
  | CheckpointSnapshot;

// ─── RecordLog interface ───────────────────────────────────────────────

/**
 * Persistence contract for the host's run_id-keyed append-only log.
 *
 * `latestCheckpoint(runId)` reads the most recent `CheckpointSnapshot`
 * for the run. It does NOT scan or replay all records (§11.1: "the
 * snapshot *is* the state"). A snapshot taken with a non-null
 * `active_role_session` whose session never reached a terminal
 * lifecycle record is treated by the host as a crash mid-session
 * (§11.1: the host records a `session_failed("crashed")` for that
 * session before re-entering the loop).
 */
export interface RecordLog {
  /**
   * Append a single record. Append-only: implementations MUST NOT
   * mutate or remove previously-appended records. Order is preserved
   * within a single `run_id`.
   */
  append(record: PersistedRecord): void;

  /**
   * The latest `CheckpointSnapshot.checkpoint` for the run, or `null`
   * if no snapshot has been appended yet (run not started).
   */
  latestCheckpoint(runId: string): Checkpoint | null;

  /**
   * All records for the run in append order. The Phase 4 host may use
   * this for `runStats()` (§11.8) and roll-up queries; the pure core
   * uses it for `rollup` (§11.6) and `buildRunMemory` (§8.4).
   */
  records(runId: string): readonly PersistedRecord[];

  /**
   * The set of `run_id`s known to this log. Used by the Phase 4
   * `listRuns()` (§11.9) entry point; the pure core does not call it.
   */
  listRunIds(): readonly string[];

  /**
   * Release any underlying resources (file handles, etc.). The in-memory
   * implementation is a no-op. The Phase 4 file-backed impl MUST close
   * its file descriptor here.
   */
  close(): void;
}

// ─── InMemoryRecordLog ──────────────────────────────────────────────────

/**
 * Pure, in-memory `RecordLog` for unit tests. The Phase 4 host owns
 * the real file-backed implementation; this one is the test double
 * (and the model the host impl should match — same semantics, same
 * interface).
 *
 * Append-only: `append` only adds; `records` returns a frozen view.
 * `latestCheckpoint` walks `records` in reverse to find the last
 * `CheckpointSnapshot` for the run. This is the host-side pattern,
 * not a violation of the "no event-sourced replay" rule (replay
 * reconstructs from events without snapshots; here we have snapshots
 * and just want the last one).
 */
export class InMemoryRecordLog implements RecordLog {
  // Maps run_id -> records (in append order). Immutable from the
  // outside: the outer Map is replaced on each append so a snapshot
  // view returned by `records()` cannot change under the caller.
  private byRun: Map<string, PersistedRecord[]> = new Map();

  append(record: PersistedRecord): void {
    // CheckpointSnapshot does not carry its own `run_id` field — the
    // wrapped Checkpoint is the source of truth for which run the
    // snapshot belongs to. Every other record shape carries `run_id`
    // directly. Routing both through one branch keeps the persistence
    // contract uniform: a snapshot is appended under its checkpoint's
    // run_id.
    const runId = record.type === "checkpoint_snapshot" ? record.checkpoint.run_id : record.run_id;
    const list = this.byRun.get(runId);
    const next = list === undefined ? [record] : [...list, record];
    this.byRun.set(runId, next);
  }

  latestCheckpoint(runId: string): Checkpoint | null {
    const list = this.byRun.get(runId);
    if (list === undefined) return null;
    // Walk in reverse: most recent snapshot first.
    for (let i = list.length - 1; i >= 0; i--) {
      const record = list[i];
      if (record && record.type === "checkpoint_snapshot") {
        return record.checkpoint;
      }
    }
    return null;
  }

  records(runId: string): readonly PersistedRecord[] {
    const list = this.byRun.get(runId);
    if (list === undefined) return Object.freeze([]);
    return Object.freeze([...list]);
  }

  listRunIds(): readonly string[] {
    return Object.freeze([...this.byRun.keys()]);
  }

  close(): void {
    // No-op for in-memory. Phase 4 file-backed impl closes its FD here.
    this.byRun = new Map();
  }
}

/**
 * pi-conductor host (SDK driver) — public surface.
 *
 * Phase 4 (Tasks 13–16.5). This is the ONLY module in the repo that
 * imports `@earendil-works/pi-coding-agent` (spec §12, plan invariant 1).
 *
 * What ships in Task 13:
 *   - `loadManifest` / `loadManifestFromString` — disk-backed manifest
 *     loader that returns a pinned `MachineDefinition` plus soft warnings.
 *   - `HostManifestError` — typed error for hard validation failures
 *     (carries structured `ManifestError` codes, not just a message).
 *   - `Host` interface + `RoleSession` + `SpawnRoleOptions` +
 *     `SeedRunMemoryArgs` — the seam the orchestration loop programs
 *     against (Tasks 14/15/15.5/16/16.5 implement it).
 *
 * What does NOT ship yet (subsequent tasks):
 *   - The SDK-backed `Host` implementation (`spawnRole` against
 *     `createAgentSession`, Task 14/15).
 *   - The file-backed `RecordLog` (Task 13.5).
 *   - The `startRun` / `resumeRun` / `listRuns` / `RunHandle` API
 *     (Task 13.5).
 *   - The orchestration loop itself (Task 15).
 *   - Post-emission sealing wrapper (Task 15.5).
 *   - The stub provider for in-CI E2E (Task 16).
 *
 * The grep-guard test in `tests/grep-guard.test.ts` does NOT scan
 * `src/host/` — this is the only directory allowed to import the
 * pi SDK, and the guard's GUARDED_DIRS list (`src/core`,
 * `src/manifest`, `src/seam`, `src/cost`) intentionally excludes it.
 */

export type {
  Host,
  RoleSession,
  SeedRunMemoryArgs,
  SpawnRoleOptions,
} from "./host.js";

export type { LoadedManifest } from "./manifest.js";
export { HostManifestError, loadManifest, loadManifestFromString } from "./manifest.js";

// ─── Per-session seam state (Task 14) ──────────────────────────────
// Mutable host state per role session: the machine-event capture
// buffer + the post-emission sealed flag. The handoff/end tool
// factories (Task 14) write to it; the loop reads from it after
// prompt() resolves; the post-emission tool wrapper (Task 15.5)
// reads the sealed flag.

export { SessionSeam } from "./seam.js";

// ─── Display tap (Phase 2) ────────────────────────────────────────────
// Display-only events from role sessions. The host emits them and the
// extension maps them to custom messages for the TUI.

export type { DisplayEvent, DisplayEventKind, DisplaySink } from "./display-sink.js";

// ─── handoff / end emission tools (Task 14) ────────────────────────
// defineTool() entries registered via customTools. The factory takes
// a SessionSeam and closes over it; the loop does not see these
// tools directly — only their effect on the seam.

export type { EmissionToolDetails } from "./tools.js";
export { createEndTool, createHandoffTool } from "./tools.js";

// ─── ask_user tool (Phase 3) ──────────────────────────────────────────
// Normal, non-terminating tool that asks the user for clarification.

export { askUserArgsSchema, createAskUserTool } from "./ask-user-tool.js";

// ─── Orchestration loop (Task 15) ─────────────────────────────────────
// The synchronous loop over role sessions. Owns `reduce` /
// `reduceLifecycle` / persistence; programs against the `Host` seam
// (Task 13). Tested against a fake host + scripted session factory
// here; Task 16 promotes that into a reusable stub provider for E2E.

export type { RunLoopOptions, RunLoopResult } from "./loop.js";
export { runLoop } from "./loop.js";

// ─── Post-emission tool sealing (Task 15.5, §12.1) ────────────────────
// Wraps every side-effecting tool so that, while the session is
// sealed (i.e., a valid handoff/end capture has been recorded), the
// tool short-circuits to an error result without invoking the
// underlying execute. Prevents work-after-handoff from mutating the
// workspace after the role has declared its exit intent.

export type { SealCheck } from "./tool-wrapper.js";
export { wrapAllToolsWithSeal, wrapToolWithSeal } from "./tool-wrapper.js";

// ─── Stub provider (Task 16, §15.3) ────────────────────────────────────
// Deterministic StreamFunction + Model that drives a real
// createAgentSession without a network or API key. The Phase 4–5
// E2E tests register this on an in-memory ModelRegistry and feed
// scripted steps (handoff, end, no_emission, fail) to drive the
// loop end-to-end in CI.

