/**
 * Public types for the pi-conductor analytics plugin.
 */

/** Configuration shape for the analytics plugin. */
export interface AnalyticsConfig {
  /** Master switch. Default: true. */
  enabled?: boolean;
  /** HTTP(S) endpoint to POST records to. Required when enabled is not false. */
  endpoint?: string;
  /** Custom HTTP headers to include in every POST. */
  headers?: Record<string, string>;
  /** Batching configuration. */
  batch?: {
    /** Enable batching. Default: true. */
    enabled?: boolean;
    /** Maximum records per batch POST. Default: 25. */
    maxRecords?: number;
    /** Maximum interval in ms before a partial batch is flushed. Default: 1000. */
    flushIntervalMs?: number;
  };
  /** Request-level configuration. */
  request?: {
    /** Request timeout in ms. Default: 5000. */
    timeoutMs?: number;
    /** Maximum retries per failed request. Default: 2. */
    maxRetries?: number;
  };
}

/** Resolved config with all defaults applied. */
export interface ResolvedConfig {
  enabled: boolean;
  endpoint: string | undefined;
  headers: Record<string, string>;
  batch: {
    enabled: boolean;
    maxRecords: number;
    flushIntervalMs: number;
  };
  request: {
    timeoutMs: number;
    maxRetries: number;
  };
}

/** The envelope sent to the configured endpoint. */
export interface AnalyticsEnvelope {
  plugin: "pi-conductor-analytics-plugin";
  plugin_version: string;
  schema_version: 1;
  sent_at: string;
  cwd: string;
  source: "pi.events:conductor:record";
  records: unknown[];
}

/** Queue item representing a record to be delivered. */
export interface QueueItem {
  records: unknown[];
}

/** Diagnostic counters exposed by the delivery queue. */
export interface QueueStats {
  enqueued: number;
  delivered: number;
  failed: number;
  dropped: number;
  pending: number;
}

/** Internal queue state for testing and diagnostics. */
export interface QueueDiagnostics {
  stats: QueueStats;
  overflowCount: number;
}

/** Per-run watermark tracking the last-sent record index. */
export interface RunWatermark {
  runId: string;
  lastSentIndex: number;
}

/**
 * Config discovery, validation, and env interpolation.
 *
 * Config lookup order (first existing file wins):
 *   1. <cwd>/.pi-conductor-analytics.json
 *   2. <cwd>/.pi/conductor-analytics.json
 *   3. <home>/.pi-conductor-analytics.json
 *   4. <home>/.config/pi-conductor/analytics.json
 */

import {
  existsSync,
  readFileSync,
  homedir,
} from "node:os";
import { join, resolve } from "node:path";
import type { AnalyticsConfig, ResolvedConfig } from "./types.js";

// ─── Helpers ───────────────────────────────────────────────────────────

const { env } = process;

/**
 * Interpolate `${ENV_VAR}` patterns in string values.
 * Leaves unrecognized patterns as-is.
 */
export function interpolateEnv(value: string): string {
  return value.replace(/\$\{([A-Za-z_][A-Za-z0-9_]*)\}/g, (_, name: string) => {
    return env[name] ?? `\$\{${name}\}`;
  });
}

// ─── Config file paths ──────────────────────────────────────────────────

function* configPaths(cwd: string, home: string): Generator<string> {
  yield join(cwd, ".pi-conductor-analytics.json");
  yield join(cwd, ".pi", "conductor-analytics.json");
  yield join(home, ".pi-conductor-analytics.json");
  yield join(home, ".config", "pi-conductor", "analytics.json");
}

// ─── Defaults ───────────────────────────────────────────────────────────

const DEFAULTS: ResolvedConfig = {
  enabled: true,
  endpoint: undefined,
  headers: {},
  batch: {
    enabled: true,
    maxRecords: 25,
    flushIntervalMs: 1000,
  },
  request: {
    timeoutMs: 5000,
    maxRetries: 2,
  },
};

// ─── Config loading ─────────────────────────────────────────────────────

/**
 * Load and resolve config from disk or return defaults.
 *
 * @param cwd  Current working directory (probe dirs 1–2).
 * @param home  Home directory (probe dirs 3–4). Defaults to `os.homedir()`.
 * @returns Tuple of [resolved config, loaded from path or null, warnings[]].
 */
export function loadConfig(
  cwd: string,
  home: string = homedir(),
): [ResolvedConfig, string | null, string[]] {
  const warnings: string[] = [];
  let raw: AnalyticsConfig | undefined;
  let sourcePath: string | null = null;

  // Find first existing config file.
  for (const p of configPaths(cwd, home)) {
    if (existsSync(p as Parameters<typeof existsSync>[0])) {
      try {
        const content = readFileSync(p as Parameters<typeof readFileSync>[0], "utf-8");
        raw = JSON.parse(content) as AnalyticsConfig;
        sourcePath = p;
        break;
      } catch (err) {
        warnings.push(`Failed to parse config at ${p}: ${(err as Error).message}`);
      }
    }
  }

