  // endpoint — required when enabled is not false
  if (typeof raw.endpoint !== "string" || raw.endpoint.trim().length === 0) {
    warnings.push(`Config at ${source}: "endpoint" is required when enabled. Disabling reporting.`);
    resolved.enabled = false;
    return [resolved, source, warnings];
  }

  // Validate endpoint URL
  const endpoint = raw.endpoint.trim();
  try {
    const url = new URL(endpoint);
    if (url.protocol !== "http:" && url.protocol !== "https:") {
      warnings.push(
        `Config at ${source}: "endpoint" protocol must be http: or https:, got "${url.protocol}". Disabling reporting.`,
      );
      resolved.enabled = false;
      return [resolved, source, warnings];
    }
  } catch {
    warnings.push(
      `Config at ${source}: "endpoint" is not a valid URL. Disabling reporting.`,
    );
    resolved.enabled = false;
    return [resolved, source, warnings];
  }
  resolved.endpoint = endpoint;

  // headers
  if (raw.headers !== undefined && typeof raw.headers === "object" && !Array.isArray(raw.headers)) {
    const interpolated: Record<string, string> = {};
    for (const [key, value] of Object.entries(raw.headers)) {
      if (typeof value === "string") {
        interpolated[key] = interpolateEnv(value);
      }
    }
    resolved.headers = interpolated;
  }

  // batch
  if (raw.batch !== undefined && typeof raw.batch === "object" && !Array.isArray(raw.batch)) {
    if (typeof raw.batch.enabled === "boolean") resolved.batch.enabled = raw.batch.enabled;
    if (typeof raw.batch.maxRecords === "number" && raw.batch.maxRecords > 0) {
      resolved.batch.maxRecords = raw.batch.maxRecords;
    }
    if (typeof raw.batch.flushIntervalMs === "number" && raw.batch.flushIntervalMs > 0) {
      resolved.batch.flushIntervalMs = raw.batch.flushIntervalMs;
    }
  }

  // request
  if (raw.request !== undefined && typeof raw.request === "object" && !Array.isArray(raw.request)) {
    if (typeof raw.request.timeoutMs === "number" && raw.request.timeoutMs > 0) {
      resolved.request.timeoutMs = raw.request.timeoutMs;
    }
    if (typeof raw.request.maxRetries === "number" && raw.request.maxRetries >= 0) {
      resolved.request.maxRetries = raw.request.maxRetries;
    }
  }

  return [resolved, source, warnings];
}

// ─── Module-level state cache ───────────────────────────────────────────

let cachedConfig: ResolvedConfig | undefined;
let cachedWarnings: string[] = [];
let cachedSourcePath: string | null = null;

/**
 * Get or load the analytics configuration.
 *
 * First call probes config paths and caches the result.
 * Subsequent calls return the cached config (caller must re-load on demand).
 *
 * @param cwd  Override CWD for testing. Defaults to `process.cwd()`.
 * @returns Tuple of [ResolvedConfig, source path or null, warnings[]].
 */
export function getConfig(
  cwd?: string,
): [ResolvedConfig, string | null, string[]] {
  if (cachedConfig !== undefined) {
    return [cachedConfig, cachedSourcePath, [...cachedWarnings]];
  }

  const wd = cwd ?? process.cwd();
  const home = homedir();
  const [config, source, warnings] = loadConfig(wd, home);

  cachedConfig = config;
  cachedSourcePath = source;
  cachedWarnings = warnings;

  return [config, source, warnings];
}

/** Clear the cached config (useful for testing). */
export function clearConfigCache(): void {
  cachedConfig = undefined;
  cachedSourcePath = null;
  cachedWarnings = [];
}

/**
 * Analytics envelope builder.
 *
 * Wraps raw conductor records in a versioned envelope for POST delivery.
 * Records are preserved unchanged inside `records[]`.
 */

import { readFileSync } from "node:fs";
import { join } from "node:path";
import type { AnalyticsEnvelope } from "./types.js";

// ─── Package version loader ─────────────────────────────────────────────

let _pluginVersion: string | undefined;

/**
 * Read the plugin version from package.json.
 * Cached after first read.
 */
function getPluginVersion(): string {
  if (_pluginVersion !== undefined) return _pluginVersion;
  try {
    // Probe CWD first, then fall back to the module's own location.
    const paths = [
      join(process.cwd(), "package.json"),
      new URL("../package.json", import.meta.url).pathname,
    ];
    for (const p of paths) {
      try {
        const pkg = JSON.parse(readFileSync(p, "utf-8")) as { version?: string };
        if (typeof pkg.version === "string") {
          _pluginVersion = pkg.version;
          return _pluginVersion;
        }
      } catch {
        continue;
      }
    }
  } catch {
    // Fallback
  }
  _pluginVersion = "0.0.0";
  return _pluginVersion;
}

/**
 * Create an analytics envelope wrapping one or more conductor records.
 *
 * @param records  One or more conductor PersistedRecord objects.
 * @param cwd      The current working directory at send time.
 * @returns A complete AnalyticsEnvelope ready for JSON serialization.
 */
export function createEnvelope(
  records: unknown[],
  cwd: string = process.cwd(),
): AnalyticsEnvelope {
  return {
    plugin: "pi-conductor-analytics-plugin",
    plugin_version: getPluginVersion(),
    schema_version: 1,
    sent_at: new Date().toISOString(),
    cwd,
    source: "pi.events:conductor:record",
    records: [...records],
  };
}

/**
 * Bounded async delivery queue for non-blocking HTTP POST delivery.
 *
 * Records are enqueued from the `conductor:record` handler and flushed
 * either on batch-size threshold or on a configurable interval.
 * The queue is bounded to prevent unbounded memory growth.
 */

import type { AnalyticsEnvelope } from "./envelope.js";
import type { ResolvedConfig, QueueStats } from "./types.js";

// ─── Constants ──────────────────────────────────────────────────────────

/** Hard cap on total pending records to prevent unbounded growth. */
const MAX_PENDING_RECORDS = 500;

// ─── Queue internals ────────────────────────────────────────────────────

type PostFunction = (
  envelope: AnalyticsEnvelope,
  config: ResolvedConfig,
) => Promise<boolean>;

/**
 * Delivery queue with batching, retries, and bounded memory.
 */
export class DeliveryQueue {
  private buffer: unknown[] = [];
  private posting = false;
  private flushTimer: ReturnType<typeof setTimeout> | null = null;
  private _stats: QueueStats = { enqueued: 0, delivered: 0, failed: 0, dropped: 0, pending: 0 };
  private _overflowCount = 0;

  // Config snapshot
  private config: ResolvedConfig;
  private postFn: PostFunction;
  private _cwd: string;

  constructor(config: ResolvedConfig, postFn: PostFunction, cwd: string) {
    this.config = config;
    this.postFn = postFn;
    this._cwd = cwd;

    if (config.batch.enabled) {
      this.startInterval();
    }
  }

  // ─── Public API ─────────────────────────────────────────────────────

  /**
   * Enqueue a record for delivery. Returns immediately.
   * Drops oldest records on overflow.
   */
  enqueue(record: unknown): void {
    if (this.buffer.length >= MAX_PENDING_RECORDS) {
      // Drop oldest
      this.buffer.shift();
      this._overflowCount++;
      this._stats.dropped++;
    }
    this.buffer.push(record);
    this._stats.enqueued++;

    if (this.config.batch.enabled && this.buffer.length >= this.config.batch.maxRecords) {
      this.flush();
    }
  }

  /**
   * Best-effort flush of pending records. Returns a promise that resolves
   * after the flush attempt (or timeout), but does not throw.
   */
  async flush(timeoutMs?: number): Promise<void> {
    if (this.posting || this.buffer.length === 0) return;

    const batch = this.buffer.splice(0, this.config.batch.maxRecords);
    this.posting = true;

    try {
      const envelope: AnalyticsEnvelope = {
        plugin: "pi-conductor-analytics-plugin",
        plugin_version: "0.1.0",
        schema_version: 1,
        sent_at: new Date().toISOString(),
        cwd: this._cwd,
        source: "pi.events:conductor:record",
        records: batch,
      };

      const result = await this.postWithTimeout(envelope, timeoutMs);
      if (result) {
        this._stats.delivered += batch.length;
      } else {
        this._stats.failed += batch.length;
      }
    } catch {
      this._stats.failed += batch.length;
    } finally {
      this.posting = false;
    }
  }

  /**
   * Flush remaining records and stop the interval timer.
   * Best-effort; does not wait indefinitely.
   */
  async shutdown(): Promise<void> {
    this.stopInterval();
    if (this.buffer.length > 0) {
      // Short timeout for shutdown flush
      await this.flush(2000);
    }
  }

  /** Get current delivery statistics. */
  stats(): QueueStats {
    this._stats.pending = this.buffer.length;
    return { ...this._stats };
  }

  /** Get the overflow drop count for diagnostics. */
  overflowCount(): number {
    return this._overflowCount;
  }

  /** Update configuration at runtime. */
  updateConfig(config: ResolvedConfig): void {
    this.config = config;
    if (!config.batch.enabled) {
      this.stopInterval();
    } else {
      this.startInterval();
    }
  }

  /** Exposed for testing: inject a different post function. */
  setPostFn(fn: PostFunction): void {
    this.postFn = fn;
  }

  // ─── Private ────────────────────────────────────────────────────────

  private async postWithTimeout(
    envelope: AnalyticsEnvelope,
    timeoutMs?: number,
  ): Promise<boolean> {
    const effectiveTimeout = timeoutMs ?? this.config.request.timeoutMs;
    const controller = new AbortController();
    const timer = setTimeout(() => controller.abort(), effectiveTimeout);

    let lastError: Error | undefined;
    for (let attempt = 0; attempt <= this.config.request.maxRetries; attempt++) {
      try {
        const ok = await this.postFn(envelope, this.config);
        clearTimeout(timer);
        return ok;
      } catch (err) {
        lastError = err instanceof Error ? err : new Error(String(err));
        if (attempt < this.config.request.maxRetries) {
          // Short delay before retry
          await new Promise((r) => setTimeout(r, 100 * (attempt + 1)));
        }
      }
    }
    clearTimeout(timer);
    return false;
  }

  private startInterval(): void {
    this.stopInterval();
    if (this.config.batch.flushIntervalMs > 0) {
      this.flushTimer = setInterval(() => {
        this.flush().catch(() => {});
      }, this.config.batch.flushIntervalMs);
    }
  }

  private stopInterval(): void {
    if (this.flushTimer !== null) {
      clearInterval(this.flushTimer);
      this.flushTimer = null;
    }
  }
}

// ─── Default POST function ──────────────────────────────────────────────

/**
 * Default HTTP POST implementation using global fetch.
 *
 * Returns `true` for 2xx responses, `false` for non-retryable failures.
 * Throws on network/retryable errors so the caller can retry.
 */
export async function defaultPost(
  envelope: AnalyticsEnvelope,
  config: ResolvedConfig,
): Promise<boolean> {
  const endpoint = config.endpoint;
  if (endpoint === undefined) return false;

  const response = await fetch(endpoint, {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
      ...config.headers,
    },
    body: JSON.stringify(envelope),
  });

  if (response.ok) return true;

  const status = response.status;
  // Retryable: 408 Request Timeout, 429 Too Many Requests, 5xx Server Error
  if (status === 408 || status === 429 || (status >= 500 && status < 600)) {
    throw new Error(`HTTP ${status}: retryable response`);
  }

  // Non-retryable: 4xx client errors, 3xx redirects, etc.
  return false;
}

/**
 * JSONL backstop / watermark — per-run watermark tracking to ship
 * records that may have been missed during a network outage or
 * late plugin load.
 *
 * Each run gets a small JSON sidecar file alongside the run's JSONL:
 *   <run_base>/.pi-conductor/runs/<run_id>.watermark.json
 *
 * The watermarks directory is derived from the conductor run base:
 *   <cwd>/.pi-conductor/runs/
 *
 * On `session_start`, the backstop walks .pi-conductor/runs/*.jsonl
 * files and ships any records past the per-run watermark.
 */

import { existsSync, readFileSync, writeFileSync, readdirSync } from "node:fs";
import { join, dirname } from "node:path";
import type { ResolvedConfig } from "./types.js";
import type { DeliveryQueue } from "./queue.js";

// ─── Default run directory ──────────────────────────────────────────────

/**
 * The default directory where pi-conductor stores run JSONL files.
 * Mirrors `DEFAULT_RUN_BASE_DIR` in pi-conductor's start.ts.
 */
export const DEFAULT_RUN_BASE_DIR = ".pi-conductor/runs";

// ─── Watermark file helpers ─────────────────────────────────────────────

interface WatermarkData {
  lastSentIndex: number;
}

function watermarkPath(runsDir: string, runId: string): string {
  return join(runsDir, `${runId}.watermark.json`);
}

function readWatermark(runsDir: string, runId: string): number {
  const wmPath = watermarkPath(runsDir, runId);
  if (!existsSync(wmPath)) return -1;
  try {
    const data = JSON.parse(readFileSync(wmPath, "utf-8")) as WatermarkData;
    return typeof data.lastSentIndex === "number" ? data.lastSentIndex : -1;
  } catch {
    return -1;
  }
}

function writeWatermark(runsDir: string, runId: string, lastSentIndex: number): void {
  const wmPath = watermarkPath(runsDir, runId);
  const data: WatermarkData = { lastSentIndex };
  writeFileSync(wmPath, JSON.stringify(data), "utf-8");
}

// ─── Run file helpers ───────────────────────────────────────────────────

interface RunFile {
  runId: string;
  filePath: string;
}

/**
 * Discover JSONL run files in the runs directory.
 */
function discoverRuns(runsDir: string): RunFile[] {
  if (!existsSync(runsDir)) return [];
  try {
    const entries = readdirSync(runsDir);
    const seen = new Set<string>();
    const result: RunFile[] = [];
    for (const entry of entries) {
      // Match `*.jsonl` but not `*.watermark.json`
      if (entry.endsWith(".jsonl") && !entry.endsWith(".watermark.json")) {
        const runId = entry.slice(0, -6); // strip ".jsonl"
        if (!seen.has(runId)) {
          seen.add(runId);
          result.push({ runId, filePath: join(runsDir, entry) });
        }
      }
    }
    return result.sort((a, b) => a.runId.localeCompare(b.runId));
  } catch {
    return [];
  }
}

/**
 * Read records from a JSONL file starting from a given index.
 * Returns the records and the count of lines read.
 */
function readRecordsFrom(
  filePath: string,
  startIndex: number,
): { records: unknown[]; lineCount: number } {
  if (!existsSync(filePath)) return { records: [], lineCount: 0 };
  try {
    const content = readFileSync(filePath, "utf-8");
    const lines = content.trim().split("\n");
    const records: unknown[] = [];
    for (let i = startIndex + 1; i < lines.length; i++) {
      const line = lines[i]?.trim();
      if (line !== undefined && line.length > 0) {
        try {
          records.push(JSON.parse(line));
        } catch {
          // Skip unparseable lines
        }
      }
    }
    return { records, lineCount: lines.length };
  } catch {
    return { records: [], lineCount: 0 };
  }
}

// ─── Backstop execution ─────────────────────────────────────────────────

/**
 * Run the JSONL backstop: walk all known JSONL run files and enqueue
 * any records past the per-run watermark.
 *
 * @param cwd   The current working directory (probe <cwd>/.pi-conductor/runs/).
 * @param queue  The delivery queue to enqueue records into.
 * @param config  The resolved config (used for batching, not delivery here).
 * @returns The number of backfill records enqueued.
 */
export function runBackstop(
  cwd: string,
  queue: DeliveryQueue,
  config: ResolvedConfig,
): number {
  const runsDir = join(cwd, DEFAULT_RUN_BASE_DIR);
  if (!existsSync(runsDir)) return 0;

  const runs = discoverRuns(runsDir);
  let totalEnqueued = 0;

  for (const run of runs) {
    const watermark = readWatermark(runsDir, run.runId);
    const { records, lineCount } = readRecordsFrom(run.filePath, watermark);

    for (const record of records) {
      queue.enqueue(record);
      totalEnqueued++;
    }

    // Update watermark to reflect all lines read
    if (lineCount > watermark + 1) {
      writeWatermark(runsDir, run.runId, lineCount - 1);
    }
  }

  return totalEnqueued;
}

/**
 * Update the watermark for a single run after the queue delivers a record.
 *
 * @param runId   The run ID to update.
 * @param index   The 0-based index of the last-sent record in the JSONL.
 */
export function updateWatermark(runId: string, index: number, cwd: string): void {
  const runsDir = join(cwd, DEFAULT_RUN_BASE_DIR);
  writeWatermark(runsDir, runId, index);
}

