        { endpoint: "https://example.com/events" },
        "/fake/path.json",
        [],
      );
      expect(config.batch.enabled).toBe(true);
      expect(config.batch.maxRecords).toBe(25);
      expect(config.batch.flushIntervalMs).toBe(1000);
    });

    it("applies custom batch config", () => {
