    capturedHandlers = new Map();
    eventBusHandlers = new Map();
    notifiedMessages = [];
    warnedMessages = [];

    const mockEventBus: EventBus = {
      emit: vi.fn(),
      on: vi.fn((channel: string, handler: (data: unknown) => void) => {
        eventBusHandlers.set(channel, handler);
        return () => eventBusHandlers.delete(channel);
      }),
    };

    return {
      on: vi.fn((event: string, handler: (...args: unknown[]) => void) => {
        capturedHandlers.set(event, handler);
      }) as unknown as ExtensionAPI["on"],
      events: mockEventBus,
      registerTool: vi.fn(),
      registerCommand: vi.fn(),
      registerShortcut: vi.fn(),
      registerFlag: vi.fn(),
      getFlag: vi.fn(),
      registerMessageRenderer: vi.fn(),
      sendMessage: vi.fn(),
      sendUserMessage: vi.fn(),
      appendEntry: vi.fn(),
      setSessionName: vi.fn(),
      getSessionName: vi.fn(),
      setLabel: vi.fn(),
      exec: vi.fn(),
      getActiveTools: vi.fn(),
      getAllTools: vi.fn(),
      setActiveTools: vi.fn(),
      getCommands: vi.fn(),
      setModel: vi.fn(),
      getThinkingLevel: vi.fn(),
      setThinkingLevel: vi.fn(),
      registerProvider: vi.fn(),
      unregisterProvider: vi.fn(),
    };
  }

  function createMockCtx() {
    return {
      ui: {
        notify: (message: string, type?: string) => {
          notifiedMessages.push(message);
        },
        select: vi.fn(),
        confirm: vi.fn(),
        input: vi.fn(),
        onTerminalInput: vi.fn(),
        setStatus: vi.fn(),
        setWorkingMessage: vi.fn(),
        setWorkingVisible: vi.fn(),
        setWorkingIndicator: vi.fn(),
        setHiddenThinkingLabel: vi.fn(),
        setWidget: vi.fn(),
        setFooter: vi.fn(),
        setHeader: vi.fn(),
        setTitle: vi.fn(),
        custom: vi.fn(),
        pasteToEditor: vi.fn(),
        setEditorText: vi.fn(),
        getEditorText: vi.fn(),
        editor: vi.fn(),
        addAutocompleteProvider: vi.fn(),
        setEditorComponent: vi.fn(),
        getEditorComponent: vi.fn(),
        theme: {} as any,
        getAllThemes: vi.fn(),
        getTheme: vi.fn(),
        setTheme: vi.fn(),
        getToolsExpanded: vi.fn(),
        setToolsExpanded: vi.fn(),
      },
      mode: "test" as any,
      hasUI: true,
      cwd: "/test",
      sessionManager: {} as any,
      modelRegistry: {} as any,
      model: undefined,
      isIdle: vi.fn(),
      isProjectTrusted: vi.fn(),
      signal: undefined,
      abort: vi.fn(),
      hasPendingMessages: vi.fn(),
      shutdown: vi.fn(),
      getContextUsage: vi.fn(),
      compact: vi.fn(),
      getSystemPrompt: vi.fn(),
    };
  }

  it("conductor:record handler validates and enqueues records", () => {
    // Create a queue directly and test the validation logic
    const config: ResolvedConfig = {
      enabled: true,
      endpoint: "https://example.com/events",
      headers: {},
      batch: { enabled: false, maxRecords: 25, flushIntervalMs: 1000 },
      request: { timeoutMs: 5000, maxRetries: 2 },
    };

    let enqueuedRecords: unknown[] = [];
    const queue = new DeliveryQueue(config, async () => true, "/cwd");

    // Intercept enqueue for testing
    const origEnqueue = queue.enqueue.bind(queue);
    queue.enqueue = (record: unknown) => {
      enqueuedRecords.push(record);
      origEnqueue(record);
    };

    const pi = createMockPi();

    // Simulate the factory logic
    pi.events.on("conductor:record", (data: unknown) => {
      if (typeof data === "object" && data !== null && typeof (data as Record<string, unknown>).type === "string") {
        queue.enqueue(data);
      }
    });

    // Emit a valid record
    const validRecord = { type: "session_started", run_id: "abc", ts: 123 };
    const handler = eventBusHandlers.get("conductor:record");
    expect(handler).toBeDefined();
    handler!(validRecord);

    expect(enqueuedRecords).toHaveLength(1);
    expect(enqueuedRecords[0]).toEqual(validRecord);

    // Emit an invalid record (should be ignored)
    enqueuedRecords = [];
    handler!("not an object");
    expect(enqueuedRecords).toHaveLength(0);

    // Emit null
    handler!(null);
    expect(enqueuedRecords).toHaveLength(0);

    // Emit an object without type field
    handler!({ foo: "bar" });
    expect(enqueuedRecords).toHaveLength(0);
  });

  it("session_start handler triggers backstop", async () => {
    const pi = createMockPi();

    // Simulate factory registering session_start
    // (this is what the extension factory does)
    let sessionStartHandler: ((event: any, ctx: any) => void) | undefined;
    pi.on = vi.fn((event: string, handler: (...args: unknown[]) => void) => {
      if (event === "session_start") {
        sessionStartHandler = handler;
      }
    }) as unknown as ExtensionAPI["on"];

    // Manually trigger the extension factory-like behavior
    const ctx = createMockCtx();
    // We can't easily test the actual backstop without pi-conductor's runs directory,
    // so we just verify the handler is registered
    expect(sessionStartHandler).toBeDefined();
  });

  it("session_shutdown handler flushes queue", async () => {
    const pi = createMockPi();
    let shutdownHandler: ((event: any, ctx: any) => void) | undefined;
    pi.on = vi.fn((event: string, handler: (...args: unknown[]) => void) => {
      if (event === "session_shutdown") {
        shutdownHandler = handler;
      }
    }) as unknown as ExtensionAPI["on"];

    const ctx = createMockCtx();
    expect(shutdownHandler).toBeDefined();
  });

  it("uses pi.events.on for conductor:record", () => {
    const pi = createMockPi();
    expect(pi.events.on).toBeDefined();

    let registered = false;
    pi.events.on("conductor:record", () => {
      registered = true;
    });

    expect(eventBusHandlers.has("conductor:record")).toBe(true);
  });
});

import { describe, it, expect, beforeEach, afterEach } from "vitest";
import { mkdtempSync, writeFileSync, mkdirSync, rmSync, existsSync } from "node:fs";
import { join } from "node:path";
import { tmpdir } from "node:os";
import { runBackstop } from "../src/watermark.js";
import { DeliveryQueue } from "../src/queue.js";
import type { ResolvedConfig } from "../src/types.js";

describe("watermark / backstop", () => {
  let tmpDir: string;
  let runsDir: string;
  let enqueued: unknown[] = [];

  const TEST_CONFIG: ResolvedConfig = {
    enabled: true,
    endpoint: "https://example.com/events",
    headers: {},
    batch: { enabled: false, maxRecords: 25, flushIntervalMs: 100000 },
    request: { timeoutMs: 5000, maxRetries: 0 },
  };

  beforeEach(() => {
    tmpDir = mkdtempSync(join(tmpdir(), "pi-analytics-wm-"));
    runsDir = join(tmpDir, ".pi-conductor", "runs");
    mkdirSync(runsDir, { recursive: true });
    enqueued = [];
  });

  afterEach(() => {
    rmSync(tmpDir, { recursive: true, force: true });
  });

  function createTestQueue(): DeliveryQueue {
    const queue = new DeliveryQueue(TEST_CONFIG, async () => true, tmpDir);
    // Override enqueue to also track records
    const origEnqueue = queue.enqueue.bind(queue);
    queue.enqueue = (record: unknown) => {
      enqueued.push(record);
      origEnqueue(record);
    };
    return queue;
  }

  it("enqueues records from JSONL files past watermark", () => {
    // Create a JSONL run file with 3 records
    const runFile = join(runsDir, "test-run-1.jsonl");
    const records = [
      { type: "session_started", run_id: "test-run-1", ts: 100 },
      { type: "transition_accepted", run_id: "test-run-1", ts: 200 },
      { type: "session_ended", run_id: "test-run-1", ts: 300 },
    ];
    writeFileSync(
      runFile,
      records.map((r) => JSON.stringify(r)).join("\n") + "\n",
    );

    // Create watermark at index 0 (skip first record)
    writeFileSync(
      join(runsDir, "test-run-1.watermark.json"),
      JSON.stringify({ lastSentIndex: 0 }),
    );

    const queue = createTestQueue();
    const count = runBackstop(tmpDir, queue, TEST_CONFIG);

    // Should have enqueued records at index > 0 (2 records: ts 200 and ts 300)
    expect(count).toBe(2);
    expect(enqueued).toHaveLength(2);
    expect(enqueued[0]).toEqual(records[1]);
    expect(enqueued[1]).toEqual(records[2]);

    // Watermark should be updated
    const wmPath = join(runsDir, "test-run-1.watermark.json");
    expect(existsSync(wmPath)).toBe(true);
  });

  it("enqueues all records when no watermark exists", () => {
    const runFile = join(runsDir, "test-run-2.jsonl");
    const records = [
      { type: "session_started", run_id: "test-run-2", ts: 100 },
      { type: "session_ended", run_id: "test-run-2", ts: 200 },
    ];
    writeFileSync(
      runFile,
      records.map((r) => JSON.stringify(r)).join("\n") + "\n",
    );

    const queue = createTestQueue();
    const count = runBackstop(tmpDir, queue, TEST_CONFIG);

    expect(count).toBe(2);
    expect(enqueued).toHaveLength(2);
  });

  it("handles empty runs directory", () => {
    const queue = createTestQueue();
    const count = runBackstop(tmpDir, queue, TEST_CONFIG);
    expect(count).toBe(0);
  });

  it("handles missing runs directory", () => {
    const noRunsDir = join(tmpDir, "nonexistent");
    const queue = createTestQueue();
    const count = runBackstop(noRunsDir, queue, TEST_CONFIG);
    expect(count).toBe(0);
  });

  it("enqueues no records when watermark is at end", () => {
    const runFile = join(runsDir, "test-run-3.jsonl");
    const records = [
      { type: "session_started", run_id: "test-run-3", ts: 100 },
    ];
    writeFileSync(
      runFile,
      records.map((r) => JSON.stringify(r)).join("\n") + "\n",
    );

    // Watermark at index 0 (0-based)
    writeFileSync(
      join(runsDir, "test-run-3.watermark.json"),
      JSON.stringify({ lastSentIndex: 0 }),
    );

    const queue = createTestQueue();
    const count = runBackstop(tmpDir, queue, TEST_CONFIG);

    // Index 0 was the only record, no new records past it
    expect(count).toBe(0);
  });
});

